:root {
  --bg-board: #0f2a4a;
  --bg-header: #0a1e36;
  --bg-card: #1a3a5c;
  --bg-card-hover: #1e4268;
  --bg-run-track: #1a3a5c;
  --color-accent: #4fc3f7;
  --color-white: #ffffff;
  --color-muted: #7fb3d3;
  --color-badge-bg: #27ae60;
  --color-badge-text: #ffffff;
  --color-date: #4fc3f7;
  --color-green-run: #27ae60;
  --color-blue-run: #2980b9;
  --color-black-run: #2c3e50;
  --color-bar-green: #27ae60;
  --color-bar-blue: #4fc3f7;
  --color-bar-black: #95a5a6;
  --color-divider: #1e4268;
  --color-lift-num: #ffffff;
  --color-lift-label: #7fb3d3;
  --border-radius-board: 16px;
  --border-radius-card: 10px;
  --border-radius-badge: 6px;
}

.board {
  background: var(--bg-board);
  border-radius: var(--border-radius-board);
  padding: 16px;
  width: 500px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.board-header {
  background: var(--bg-header);
  border-radius: var(--border-radius-card);
  padding: 12px 16px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.resort-name {
  font-size: 20px;
  font-weight: 800;
  color: var(--color-white);
  letter-spacing: 3px;
}

.board-meta {
  display: flex;
  align-items: center;
  gap: 10px;
}

.status-badge {
  background: var(--color-badge-bg);
  color: var(--color-badge-text);
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 1px;
  padding: 3px 10px;
  border-radius: var(--border-radius-badge);
}

.date-label {
  font-size: 13px;
  font-weight: 600;
  color: var(--color-date);
  letter-spacing: 1px;
}

.conditions-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px;
}

.condition-card {
  background: var(--bg-card);
  border-radius: var(--border-radius-card);
  padding: 12px 8px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.condition-icon {
  font-size: 18px;
  line-height: 1;
}

.condition-value {
  font-size: 22px;
  font-weight: 800;
  color: var(--color-white);
  line-height: 1;
}

.unit {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-muted);
}

.condition-label {
  font-size: 11px;
  font-weight: 500;
  color: var(--color-muted);
  text-align: center;
}

.runs-section {
  background: var(--bg-header);
  border-radius: var(--border-radius-card);
  padding: 12px 14px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.run-row {
  display: flex;
  align-items: center;
  gap: 10px;
}

.run-dot {
  width: 12px;
  height: 12px;
  border-radius: 50%;
  flex-shrink: 0;
}

.run-dot.green { background: var(--color-green-run); }
.run-dot.blue  { background: var(--color-blue-run); }
.run-dot.black { background: var(--color-black-run); border: 2px solid var(--color-muted); }

.run-name {
  font-size: 13px;
  font-weight: 600;
  color: var(--color-white);
  width: 80px;
}

.run-count {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-muted);
  width: 52px;
  text-align: right;
}

.run-bar-track {
  flex: 1;
  height: 8px;
  background: var(--bg-run-track);
  border-radius: 4px;
  overflow: hidden;
}

.run-bar {
  height: 100%;
  border-radius: 4px;
}

.run-row:nth-child(1) .run-bar { background: var(--color-bar-green); }
.run-row:nth-child(2) .run-bar { background: var(--color-bar-blue); }
.run-row:nth-child(3) .run-bar { background: var(--color-bar-black); }

.lifts-row {
  background: var(--bg-header);
  border-radius: var(--border-radius-card);
  padding: 10px 14px;
  display: flex;
  align-items: center;
  justify-content: space-around;
}

.lift-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.lift-num {
  font-size: 20px;
  font-weight: 800;
  color: var(--color-lift-num);
  line-height: 1;
}

.lift-unit {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-muted);
}

.lift-label {
  font-size: 11px;
  font-weight: 500;
  color: var(--color-lift-label);
}

.lift-divider {
  width: 1px;
  height: 32px;
  background: var(--color-divider);
}
